import { createClient } from '@supabase/supabase-js';

// In a real application, these would come strictly from environment variables.
// For this demo/code generation context, we check if they exist.
// If the user hasn't set up Supabase yet, the AuthContext will handle the fallback/mock mode.

const supabaseUrl = process.env.REACT_APP_SUPABASE_URL || process.env.SUPABASE_URL || '';
const supabaseAnonKey = process.env.REACT_APP_SUPABASE_ANON_KEY || process.env.SUPABASE_ANON_KEY || '';

// Create a single supabase client for interacting with your database
export const supabase = createClient(
  supabaseUrl || 'https://placeholder.supabase.co', 
  supabaseAnonKey || 'placeholder'
);

// Helper to check if supabase is configured
export const isSupabaseConfigured = () => {
  return supabaseUrl && supabaseAnonKey && supabaseUrl !== 'https://placeholder.supabase.co';
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';
import { User, Session } from '@supabase/supabase-js';

interface AuthContextType {
  user: User | null;
  session: Session | null;
  loading: boolean;
  signIn: (email: string) => Promise<{ error: any }>; // Using magic link or password
  signOut: () => Promise<void>;
  isMockMode: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);

  // If no env vars are provided, we run in "Mock Mode" to allow the UI to function
  const isMockMode = !isSupabaseConfigured();

  useEffect(() => {
    if (isMockMode) {
      // Check local storage for mock user
      const mockUser = localStorage.getItem('rezumate_mock_user');
      if (mockUser) {
        setUser(JSON.parse(mockUser));
      }
      setLoading(false);
      return;
    }

    // Real Supabase Logic
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setUser(session?.user ?? null);
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      setUser(session?.user ?? null);
    });

    return () => subscription.unsubscribe();
  }, [isMockMode]);

  const signIn = async (email: string) => {
    if (isMockMode) {
      // Mock login
      const mockUser = {
        id: 'mock-user-id',
        email: email,
        app_metadata: {},
        user_metadata: {},
        aud: 'authenticated',
        created_at: new Date().toISOString()
      };
      localStorage.setItem('rezumate_mock_user', JSON.stringify(mockUser));
      setUser(mockUser as User);
      return { error: null };
    }

    // Real Supabase Login (Magic Link for simplicity in this demo, or expand to password)
    // For this implementation, let's assume passwordless magic link to minimize UI complexity,
    // OR we can implement password auth if the UI provides it. 
    // The UI provided in the request asked for "Login" and "Signup", usually implying password.
    // However, the `signInWithOtp` is often easier to setup. 
    // Let's implement a generic "signIn" that we will trigger from the Login page. 
    // We'll actually handle the specific API calls in the Login/Signup components 
    // but update state here if needed. 
    // Actually, onAuthStateChange handles the state.
    return { error: null };
  };

  const signOut = async () => {
    if (isMockMode) {
      localStorage.removeItem('rezumate_mock_user');
      setUser(null);
      return;
    }
    await supabase.auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, session, loading, signIn, signOut, isMockMode }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import React, { useState } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';
import { Loader2, ArrowLeft, Mail, Lock } from 'lucide-react';
import { motion } from 'framer-motion';

interface LoginPageProps {
  onBack: () => void;
  onSignup: () => void;
  onSuccess: () => void;
}

export default function LoginPage({ onBack, onSignup, onSuccess }: LoginPageProps) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const { signIn, isMockMode } = useAuth();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);

    try {
      if (isMockMode) {
        // Mock login via context
        await signIn(email);
        onSuccess();
      } else {
        // Real Supabase login
        const { error } = await supabase.auth.signInWithPassword({
          email,
          password,
        });
        if (error) throw error;
        onSuccess();
      }
    } catch (err: any) {
      setError(err.message || 'Failed to login');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#F9FAFB] dark:bg-black flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="max-w-md w-full bg-white dark:bg-[#0A0A0A] border border-gray-200 dark:border-gray-800 rounded-2xl shadow-xl overflow-hidden"
      >
        <div className="p-8">
            <button onClick={onBack} className="flex items-center gap-2 text-sm text-gray-500 hover:text-black dark:hover:text-white mb-6 transition-colors">
                <ArrowLeft size={16} /> Back
            </button>

            <div className="mb-8">
                <h2 className="text-2xl font-bold font-mono dark:text-white">Welcome Back</h2>
                <p className="text-gray-500 dark:text-gray-400 text-sm mt-2">Enter your credentials to access your workspace.</p>
                {isMockMode && (
                   <p className="text-[10px] mt-2 text-amber-600 bg-amber-50 dark:bg-amber-900/20 px-2 py-1 rounded inline-block">
                     Demo Mode: Enter any email/password
                   </p>
                )}
            </div>

            <form onSubmit={handleLogin} className="space-y-4">
                <div>
                    <label className="block text-xs font-bold font-mono text-gray-500 uppercase mb-1.5">Email</label>
                    <div className="relative">
                        <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
                        <input 
                            type="email" 
                            required
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-lg text-sm font-mono focus:ring-2 focus:ring-black dark:focus:ring-white outline-none dark:text-white transition-all"
                            placeholder="you@example.com"
