                    </div>
                </div>

                <div>
                    <label className="block text-xs font-bold font-mono text-gray-500 uppercase mb-1.5">Password</label>
                    <div className="relative">
                        <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
                        <input 
                            type="password" 
                            required
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-lg text-sm font-mono focus:ring-2 focus:ring-black dark:focus:ring-white outline-none dark:text-white transition-all"
