        // Initialize with mock data if no saved resumes
        const mockResumes = MOCK_RESUMES;
        setResumes(mockResumes);
        mockResumes.forEach(resume => saveResume(resume));
      }

      // Load chat messages
      const savedChatMessages = getChatMessages();
      setChatMessages(savedChatMessages);

