      const initialMessage = { role: 'ai' as const, text: initialPrompt || (resume ? `Hi! I've loaded "${resume.title}". Ask me anything about it.` : "Hi! How can I help you with your interview prep today?") };
      setChatMessages([initialMessage]);
      setIsChatOpen(true);
