                onClick={() => setIsMobileMenuOpen(false)}
                className="fixed inset-0 bg-black/50 z-30 md:hidden"
                style={{ top: '64px' }}
            />
        )}
      </AnimatePresence>

      {/* Sidebar */}
      <aside className={`
          w-64 bg-white dark:bg-[#0A0A0A] border-r border-gray-200 dark:border-gray-800 flex flex-col fixed h-[calc(100vh-64px)] z-40 transition-transform duration-300 top-16
          ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0
      `}>
          <div className="flex-1 py-6 px-4 space-y-2 overflow-y-auto scrollbar-thin scrollbar-thumb-gray-200 dark:scrollbar-thumb-gray-800">
              <SidebarItem 
                  icon={<LayoutDashboard size={20} />} 
                  label="Overview" 
